class Solution:
    def minimumAverage(self, nums: List[int]) -> float:
        averages = []
        while nums:
            minElement = min(nums)
            maxElement = max(nums)
            avg = (minElement + maxElement) / 2
            averages.append(avg)
            nums.remove(minElement)
            nums.remove(maxElement)
        return min(averages)
